  "inlineSchema": "// -----------------------------------------------\n// Portfolio Platform — Database Schema (Prisma)\n// Auth managed by Clerk — no sessions/accounts\n// -----------------------------------------------\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nmodel User {\n  id        String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  clerkId   String   @unique @map(\"clerk_id\") /// Clerk user ID — sync via webhook\n  email     String   @unique\n  username  String   @unique /// Used as portfolio URL slug\n  fullName  String?  @map(\"full_name\")\n  avatarUrl String?  @map(\"avatar_url\")\n  role      String   @default(\"user\") /// user | admin\n  plan      String   @default(\"free\") /// free | pro\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @default(now()) @updatedAt @map(\"updated_at\")\n\n  portfolio     Portfolio?\n  subscriptions Subscription[]\n\n  @@map(\"users\")\n}\n\nmodel Subscription {\n  id                   String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  userId               String   @map(\"user_id\") @db.Uuid\n  stripeCustomerId     String   @unique @map(\"stripe_customer_id\")\n  stripeSubscriptionId String   @unique @map(\"stripe_subscription_id\")\n  plan                 String /// free | pro\n  status               String /// active | trialing | past_due | canceled\n  currentPeriodEnd     DateTime @map(\"current_period_end\")\n  createdAt            DateTime @default(now()) @map(\"created_at\")\n  updatedAt            DateTime @default(now()) @updatedAt @map(\"updated_at\")\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@map(\"subscriptions\")\n}\n\nmodel Theme {\n  id              String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  slug            String   @unique /// Maps to /themes/[slug]/index.tsx\n  name            String\n  description     String?\n  previewImageUrl String?  @map(\"preview_image_url\")\n  tier            String   @default(\"free\") /// free | pro\n  isPublished     Boolean  @default(false) @map(\"is_published\")\n  createdAt       DateTime @default(now()) @map(\"created_at\")\n\n  portfolios Portfolio[]\n\n  @@map(\"themes\")\n}\n\nmodel Portfolio {\n  id          String    @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  userId      String    @unique @map(\"user_id\") @db.Uuid\n  themeId     String    @map(\"theme_id\") @db.Uuid\n  slug        String    @unique /// Public URL — username.app.com/[slug]\n  isPublished Boolean   @default(false) @map(\"is_published\")\n  publishedAt DateTime? @map(\"published_at\")\n  updatedAt   DateTime  @default(now()) @updatedAt @map(\"updated_at\")\n\n  user          User           @relation(fields: [userId], references: [id])\n  theme         Theme          @relation(fields: [themeId], references: [id])\n  hero          Hero?\n  experiences   Experience[]\n  projects      Project[]\n  skills        Skill[]\n  links         Link[]\n  domainMapping DomainMapping?\n\n  @@map(\"portfolios\")\n}\n\nmodel Hero {\n  id          String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  portfolioId String   @unique @map(\"portfolio_id\") @db.Uuid /// One hero per portfolio\n  headline    String\n  subheadline String?\n  bio         String?\n  avatarUrl   String?  @map(\"avatar_url\")\n  location    String?\n  openToWork  Boolean  @default(false) @map(\"open_to_work\")\n  ctaLabel    String?  @map(\"cta_label\") /// e.g. Download CV\n  ctaUrl      String?  @map(\"cta_url\")\n  updatedAt   DateTime @default(now()) @updatedAt @map(\"updated_at\")\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id])\n\n  @@map(\"heros\")\n}\n\nmodel Experience {\n  id          String    @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  portfolioId String    @map(\"portfolio_id\") @db.Uuid\n  company     String\n  role        String\n  description String?\n  startDate   DateTime  @map(\"start_date\") @db.Date\n  endDate     DateTime? @map(\"end_date\") @db.Date /// null = current role\n  isCurrent   Boolean   @default(false) @map(\"is_current\")\n  sortOrder   Int       @default(0) @map(\"sort_order\")\n  createdAt   DateTime  @default(now()) @map(\"created_at\")\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id])\n\n  @@map(\"experiences\")\n}\n\nmodel Project {\n  id            String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  portfolioId   String   @map(\"portfolio_id\") @db.Uuid\n  title         String\n  description   String?\n  coverImageUrl String?  @map(\"cover_image_url\")\n  url           String? /// Live project URL\n  repoUrl       String?  @map(\"repo_url\") /// GitHub / GitLab URL\n  featured      Boolean  @default(false)\n  sortOrder     Int      @default(0) @map(\"sort_order\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  portfolio     Portfolio      @relation(fields: [portfolioId], references: [id])\n  projectSkills ProjectSkill[]\n\n  @@map(\"projects\")\n}\n\nmodel Skill {\n  id          String  @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  portfolioId String  @map(\"portfolio_id\") @db.Uuid\n  name        String\n  category    String? /// e.g. Frontend, Backend, Design, Tools\n  sortOrder   Int     @default(0) @map(\"sort_order\")\n\n  portfolio     Portfolio      @relation(fields: [portfolioId], references: [id])\n  projectSkills ProjectSkill[]\n\n  @@map(\"skills\")\n}\n\nmodel ProjectSkill {\n  projectId String @map(\"project_id\") @db.Uuid\n  skillId   String @map(\"skill_id\") @db.Uuid\n\n  project Project @relation(fields: [projectId], references: [id])\n  skill   Skill   @relation(fields: [skillId], references: [id])\n\n  @@id([projectId, skillId])\n  @@map(\"project_skills\")\n}\n\nmodel Link {\n  id          String  @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  portfolioId String  @map(\"portfolio_id\") @db.Uuid\n  platform    String /// github | linkedin | twitter | dribbble | email | other\n  label       String? /// Custom display label\n  url         String\n  sortOrder   Int     @default(0) @map(\"sort_order\")\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id])\n\n  @@map(\"links\")\n}\n\nmodel DomainMapping {\n  id                String    @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  portfolioId       String    @unique @map(\"portfolio_id\") @db.Uuid\n  customDomain      String    @unique @map(\"custom_domain\")\n  verified          Boolean   @default(false)\n  verificationToken String    @map(\"verification_token\")\n  verifiedAt        DateTime? @map(\"verified_at\")\n  createdAt         DateTime  @default(now()) @map(\"created_at\")\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id])\n\n  @@map(\"domain_mappings\")\n}\n"
